import { AttributeTypeMap } from "../../datadog-api-client-common/util";

/**
 * A single node within a RUM operation journey step, matching RUM events with a query.
 */
export class RUMOperationJourneyNode {
  /**
   * The unique identifier of the node. Generated by the server if omitted.
   */
  "id"?: string;
  /**
   * The RUM search query used to match events for this node.
   */
  "query": string;

  /**
   * A container for additional, undeclared properties.
   * This is a holder for any undeclared properties as specified with
   * the 'additionalProperties' keyword in the OAS document.
   */
  "additionalProperties"?: { [key: string]: any };

  /**
   * @ignore
   */
  "_unparsed"?: boolean;

  /**
   * @ignore
   */
  static readonly attributeTypeMap: AttributeTypeMap = {
    id: {
      baseName: "id",
      type: "string",
    },
    query: {
      baseName: "query",
      type: "string",
      required: true,
    },
    additionalProperties: {
      baseName: "additionalProperties",
      type: "{ [key: string]: any; }",
    },
  };

  /**
   * @ignore
   */
  static getAttributeTypeMap(): AttributeTypeMap {
    return RUMOperationJourneyNode.attributeTypeMap;
  }

  public constructor() {}
}
